import { describe, it, expect } from 'vitest';
import { BettyCompiler } from './compiler';
import { compileToGrassmannian } from './grassmannian-compiler';

describe('Mudras Geometric Crystallography', () => {

  it('should compile a valid positive Grassmannian topology', () => {
    const src = `
(start:Clinamen)
(start)-[:FORK]->(v1:State)
(v1)-[:FOLD]->(end:Vacuum)
    `;
    const compiler = new BettyCompiler();
    const ast = compiler.parse(src).ast!;
    
    expect(() => compileToGrassmannian(ast)).not.toThrow();
  });

  it('should trigger Schubert Calculus Type Mismatch (Disjoint Topology)', () => {
    const src = `
(start:Clinamen)
(start)-[:FORK]->(v1:State)

(other:Isolated)
(other)-[:PROCESS]->(v2:Isolated)
    `;
    const compiler = new BettyCompiler();
    const ast = compiler.parse(src).ast!;
    
    expect(() => compileToGrassmannian(ast)).toThrowError(/Schubert Calculus failure: Intersection volume is exactly 0/);
  });

  it('should trigger Cohomological Obstruction (Deadlock / Topologic Hole)', () => {
    const src = `
(start:Clinamen)
(start)-[:FORK]->(v1:State)
(v1)-[:PROCESS]->(v2:State)
(v2)-[:FORK]->(v1)
    `;
    const compiler = new BettyCompiler();
    const ast = compiler.parse(src).ast!;
    
    expect(() => compileToGrassmannian(ast)).toThrowError(/Cohomological Obstruction: 1st Betti Number/);
  });

});
